addEventListener('fetch', event => {
  event.respondWith(handle(event.request))
})

async function handle(req) {
  // KV namespace bound to script as NAMESPACE
  const value = await NAMESPACE.get('site:config')
  if (value) return new Response(value, { status: 200 })

  // fallback to origin (rare), then populate KV
  const originResp = await fetch('https://origin.example.com/config.json')
  const body = await originResp.text()
  await NAMESPACE.put('site:config', body)
  return new Response(body, { status: 200 })
}

